import { Component, ChangeDetectionStrategy, input, computed } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { badgeVariants, type BadgeVariants } from './badge.variants';

@Component({
  selector: 'n-badge',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    '[class]': 'classes()',
    'data-slot': 'badge',
  },
})
export class BadgeComponent {
  readonly nVariant = input<BadgeVariants['nVariant']>('default');
  readonly nClass   = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses(badgeVariants({ nVariant: this.nVariant() }), this.nClass()),
  );
}

import { cva, type VariantProps } from 'class-variance-authority';

export const badgeVariants = cva(
  'inline-flex items-center justify-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors select-none',
  {
    variants: {
      nVariant: {
        default:     'border-transparent bg-primary text-primary-foreground',
        secondary:   'border-transparent bg-secondary text-secondary-foreground',
        destructive: 'border-transparent bg-destructive text-destructive-foreground',
        outline:     'border-border text-foreground',
        success:     'border-transparent bg-green-500 text-white',
        warning:     'border-transparent bg-amber-400 text-white',
      },
    },
    defaultVariants: {
      nVariant: 'default',
    },
  },
);

export type BadgeVariants = VariantProps<typeof badgeVariants>;

